@font-face {
  font-family: 'PrimaryWebFont';
  src: url('/fonts/PrimaryWebFont.woff2') format('woff2');
  font-display: swap;
  /* These values are examples; calculate based on your primary font's actual metrics */
  ascent-override: 95%; /* Adjust to match the primary font's ascent */
  descent-override: 25%; /* Adjust to match the primary font's descent */
  line-gap-override: 10%; /* Adjust to match the primary font's line gap */
}

body {
  font-family: 'PrimaryWebFont', 'Arial', sans-serif;
}
